const envelope = $input.first().json;
const root = typeof envelope.data === 'string' ? JSON.parse(envelope.data) : envelope;
const definitions = root.definitions ?? root.components?.schemas ?? {};
const tableNames = [
  'profit_anchor_service_templates',
  'profit_anchor_agreements',
  'profit_anchor_invoices',
  'profit_anchor_invoice_line_items',
  'profit_staff',
];

return tableNames.map((tableName) => {
  const schema = definitions[tableName];
  const properties = schema?.properties ?? {};

  return {
    json: {
      tableName,
      found: Boolean(schema),
      required: schema?.required ?? [],
      columns: Object.entries(properties).map(([name, definition]) => ({
        name,
        type: definition.type ?? null,
        format: definition.format ?? null,
        default: definition.default ?? null,
        description: definition.description ?? null,
      })),
    },
  };
});
